package com.example.loginprototype;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.util.UUID;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private ProgressBar progress;
    private TextView errorText;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (AuthStore.isLoggedIn(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        progress = findViewById(R.id.progress);
        errorText = findViewById(R.id.errorText);

        progress.setVisibility(View.GONE);
        errorText.setText("");

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        errorText.setText("");

        String email = emailInput.getText() == null ? "" : emailInput.getText().toString().trim();
        String password = passwordInput.getText() == null ? "" : passwordInput.getText().toString();

        if (TextUtils.isEmpty(email)) {
            errorText.setText("Email is required");
            return;
        }
        if (TextUtils.isEmpty(password)) {
            errorText.setText("Password is required");
            return;
        }

        setLoading(true);

        FakeAuthApi.login(email, password, new FakeAuthApi.Callback() {
            @Override
            public void onSuccess(String authToken) {
                AuthStore.save(LoginActivity.this, email, authToken);
                setLoading(false);
                startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                finish();
            }

            @Override
            public void onError(String message) {
                setLoading(false);
                errorText.setText(message);
            }
        });
    }

    private void setLoading(boolean loading) {
        progress.setVisibility(loading ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!loading);
        emailInput.setEnabled(!loading);
        passwordInput.setEnabled(!loading);
    }
}

class HomeActivity extends AppCompatActivity {

    private TextView welcomeText;
    private TextView tokenText;
    private Button logoutButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!AuthStore.isLoggedIn(this)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_home);

        welcomeText = findViewById(R.id.welcomeText);
        tokenText = findViewById(R.id.tokenText);
        logoutButton = findViewById(R.id.logoutButton);

        String email = AuthStore.getEmail(this);
        String token = AuthStore.getToken(this);

        welcomeText.setText("Logged in as: " + (email == null ? "" : email));
        tokenText.setText("Token: " + (token == null ? "" : token));

        logoutButton.setOnClickListener(v -> {
            AuthStore.clear(HomeActivity.this);
            startActivity(new Intent(HomeActivity.this, LoginActivity.class));
            finish();
        });
    }
}

final class AuthStore {
    private static final String PREFS = "auth_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "token";

    private AuthStore() {}

    static void save(Context context, String email, String token) {
        SharedPreferences sp = context.getSharedPreferences(PREFS, Context.MODE_PRIVATE);
        sp.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    static boolean isLoggedIn(Context context) {
        return !TextUtils.isEmpty(getToken(context)) && !TextUtils.isEmpty(getEmail(context));
    }

    @Nullable
    static String getEmail(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS, Context.MODE_PRIVATE);
        return sp.getString(KEY_EMAIL, null);
    }

    @Nullable
    static String getToken(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS, Context.MODE_PRIVATE);
        return sp.getString(KEY_TOKEN, null);
    }

    static void clear(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS, Context.MODE_PRIVATE);
        sp.edit().clear().apply();
    }
}

final class FakeAuthApi {

    interface Callback {
        void onSuccess(String authToken);
        void onError(String message);
    }

    private FakeAuthApi() {}

    static void login(String email, String password, Callback callback) {
        new Thread(() -> {
            try {
                Thread.sleep(700);
            } catch (InterruptedException ignored) {}

            boolean ok = password.length() >= 4;

            String token = ok ? "demo_" + UUID.randomUUID().toString() : null;

            android.os.Handler main = new android.os.Handler(android.os.Looper.getMainLooper());
            main.post(() -> {
                if (ok) callback.onSuccess(token);
                else callback.onError("Invalid credentials (demo: password must be 4+ chars)");
            });
        }).start();
    }
}